,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select task_id,',
'       due_date,',
'       task_key,',
'       title,',
'       status_name,',
'       priority_code,',
'       team_name,',
'       application_name,',
'       assignees,',
'       apex_page.get_url(',
'           p_page => 12,',
