,p_prompt=>'Assignee'
,p_source_type=>'ALWAYS_NULL'
,p_display_as=>'NATIVE_SELECT_LIST'
,p_lov=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select u.display_name || '' - '' || t.team_name as display_value,',
'       tm.team_member_id as return_value',
'  from tsk_team_members tm',
'  join tsk_users u',
'    on u.user_id = tm.user_id',
'  join tsk_teams t',
'    on t.team_id = tm.team_id',
'  join tsk_tasks task',
'    on task.team_id = tm.team_id',
' where task.task_id = :P14_TASK_ID',
'   and tm.active_yn = ''Y''',
'   and u.active_yn = ''Y''',
'   and t.active_yn = ''Y''',
'   and not exists (',
'           select 1',
'             from tsk_task_assignees ta',
'            where ta.task_id = :P14_TASK_ID',
'              and ta.team_member_id = tm.team_member_id',
'              and ta.active_yn = ''Y'' )',
' order by u.display_name'))
