,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Add Assignee'
,p_static_id=>'add-assignee'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    l_display_name tsk_users.display_name%type;',
'begin',
'    if :P14_TEAM_MEMBER_ID is null then',
'        raise_application_error(-20001, ''Select an assignee.'');',
'    end if;',
'',
'    select u.display_name',
'      into l_display_name',
'      from tsk_team_members tm',
'      join tsk_users u',
'        on u.user_id = tm.user_id',
'     where tm.team_member_id = :P14_TEAM_MEMBER_ID;',
'',
'    update tsk_task_assignees',
'       set active_yn = ''Y'',',
'           unassigned_on = null,',
'           assignment_role = :P14_ASSIGNMENT_ROLE,',
'           allocated_pct = :P14_ALLOCATED_PCT,',
'           updated_at = systimestamp,',
'           updated_by = :APP_USER',
'     where task_id = :P14_TASK_ID',
'       and team_member_id = :P14_TEAM_MEMBER_ID',
'       and active_yn = ''N'';',
'',
'    if sql%rowcount = 0 then',
'        insert into tsk_task_assignees (',
'            task_id,',
'            team_member_id,',
'            assignment_role,',
'            allocated_pct',
'        ) values (',
'            :P14_TASK_ID,',
'            :P14_TEAM_MEMBER_ID,',
'            :P14_ASSIGNMENT_ROLE,',
'            :P14_ALLOCATED_PCT',
'        );',
'    end if;',
'',
'    insert into tsk_change_log (',
'        entity_name,',
'        entity_pk,',
'        task_id,',
'        change_action,',
'        change_note,',
'        changed_by',
'    ) values (',
'        ''TASK'',',
'        :P14_TASK_ID,',
'        :P14_TASK_ID,',
'        ''ASSIGN'',',
'        ''Assignee added: '' || l_display_name,',
'        :APP_USER',
'    );',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(39419642309090026)
,p_process_success_message=>'Assignee added'
,p_internal_uid=>16527611783502004
);
