wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(39392601574635769)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Create Member'
,p_static_id=>'create-member'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    l_user_id tsk_users.user_id%type;',
'begin',
'    begin',
'        select user_id',
'          into l_user_id',
'          from tsk_users',
'         where lower(username) = lower(:P22_USERNAME);',
'    exception',
'        when no_data_found then',
'            begin',
'                select user_id',
'                  into l_user_id',
'                  from tsk_users',
'                 where lower(email) = lower(:P22_EMAIL);',
'            exception',
'                when no_data_found then',
'                    insert into tsk_users (',
'                        username,',
'                        display_name,',
'                        email',
'                    ) values (',
'                        lower(:P22_USERNAME),',
'                        :P22_DISPLAY_NAME,',
'                        lower(:P22_EMAIL)',
'                    )',
'                    returning user_id into l_user_id;',
'            end;',
'    end;',
'',
'    begin',
'        insert into tsk_team_members (',
'            team_id,',
'            user_id,',
'            role_name,',
'            joined_on',
'        ) values (',
'            :P22_TEAM_ID,',
'            l_user_id,',
'            :P22_ROLE_NAME,',
'            nvl(:P22_JOINED_ON, trunc(sysdate))',
'        );',
'    exception',
'        when dup_val_on_index then',
'            raise_application_error(-20001, ''This member is already assigned to the selected team.'');',
'    end;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(39392240004635769)
,p_internal_uid=>16500288370047746
);
end;
