,p_plug_template=>2102002977963900996
,p_plug_display_sequence=>20
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select a.application_id,',
'       t.team_name,',
'       a.application_code,',
'       a.application_name,',
'       count(tsk.task_id) as task_count,',
'       sum(case when s.status_code = ''BACKLOG'' then 1 else 0 end) as backlog_tasks,',
'       sum(case when s.status_code = ''NOT_STARTED'' then 1 else 0 end) as not_started_tasks,',
'       sum(case when s.status_code = ''IN_PROGRESS'' then 1 else 0 end) as in_progress_tasks,',
'       sum(case when s.status_code = ''IN_REVIEW'' then 1 else 0 end) as in_review_tasks,',
'       sum(case when s.status_code = ''BLOCKED'' then 1 else 0 end) as blocked_tasks,',
'       sum(case when s.status_code = ''COMPLETED'' then 1 else 0 end) as completed_tasks,',
'       apex_page.get_url(',
'           p_page => 10,',
'           p_clear_cache => ''10'',',
'           p_items => ''P10_APPLICATION'',',
'           p_values => a.application_name',
'       ) as task_count_url,',
'       apex_page.get_url(',
'           p_page => 10,',
'           p_clear_cache => ''10'',',
'           p_items => ''P10_APPLICATION,P10_STATUS'',',
'           p_values => a.application_name || '',Backlog''',
'       ) as backlog_tasks_url,',
'       apex_page.get_url(',
'           p_page => 10,',
'           p_clear_cache => ''10'',',
'           p_items => ''P10_APPLICATION,P10_STATUS'',',
'           p_values => a.application_name || '',Not Started''',
'       ) as not_started_tasks_url,',
'       apex_page.get_url(',
'           p_page => 10,',
'           p_clear_cache => ''10'',',
'           p_items => ''P10_APPLICATION,P10_STATUS'',',
'           p_values => a.application_name || '',In Progress''',
'       ) as in_progress_tasks_url,',
'       apex_page.get_url(',
'           p_page => 10,',
'           p_clear_cache => ''10'',',
'           p_items => ''P10_APPLICATION,P10_STATUS'',',
'           p_values => a.application_name || '',In Review''',
'       ) as in_review_tasks_url,',
'       apex_page.get_url(',
'           p_page => 10,',
'           p_clear_cache => ''10'',',
'           p_items => ''P10_APPLICATION,P10_STATUS'',',
'           p_values => a.application_name || '',Blocked''',
'       ) as blocked_tasks_url,',
'       apex_page.get_url(',
'           p_page => 10,',
'           p_clear_cache => ''10'',',
'           p_items => ''P10_APPLICATION,P10_STATUS'',',
'           p_values => a.application_name || '',Completed''',
'       ) as completed_tasks_url',
'  from tsk_applications a',
'  left join tsk_teams t',
'    on t.team_id = a.owner_team_id',
'  left join tsk_tasks tsk',
'    on tsk.application_id = a.application_id',
'  left join tsk_statuses s',
'    on s.status_id = tsk.status_id',
' group by a.application_id,',
'          t.team_name,',
'          a.application_code,',
'          a.application_name',
' order by t.team_name, a.application_name'))
