 p_id=>wwv_flow_imp.id(32882321204589024)
,p_name=>'Topic Groups'
,p_static_id=>'topic-groups'
,p_template=>4073835273271169698
,p_display_sequence=>10
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--stretch:t-Report--rowHighlight'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select tg.topic_group_id,',
'       apex_page.get_url(',
'           p_page => 80,',
'           p_clear_cache => ''80'',',
'           p_items => ''P80_TOPIC_GROUP_ID'',',
'           p_values => tg.topic_group_id',
'       ) as select_url,',
'       apex_page.get_url(',
'           p_page => 81,',
'           p_clear_cache => ''81'',',
'           p_items => ''P81_TOPIC_GROUP_ID'',',
'           p_values => tg.topic_group_id',
'       ) as edit_url,',
'       tg.topic_name,',
'       tg.description,',
'       tg.active_yn,',
'       count(t.task_id) as task_count,',
'       min(t.due_date) as next_due_date,',
'       tg.updated_at,',
'       tg.updated_by',
'  from tsk_topic_groups tg',
'  left join tsk_task_topic_groups ttg',
'    on ttg.topic_group_id = tg.topic_group_id',
'  left join tsk_tasks t',
'    on t.task_id = ttg.task_id',
' group by tg.topic_group_id,',
'          tg.topic_name,',
'          tg.description,',
'          tg.active_yn,',
'          tg.updated_at,',
'          tg.updated_by',
' order by tg.topic_name'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
,p_query_row_template=>2540130677583398057
,p_query_num_rows=>15
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_query_no_data_found=>'No topic groups found'
