,p_name=>'Tasks in Topic'
,p_static_id=>'topic-tasks'
,p_template=>4073835273271169698
,p_display_sequence=>20
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--stretch:t-Report--rowHighlight'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select t.task_id,',
'       apex_page.get_url(',
'           p_page => 12,',
'           p_items => ''P12_TASK_ID'',',
'           p_values => t.task_id',
'       ) as task_url,',
'       t.task_key,',
'       t.title,',
'       s.status_name,',
'       t.priority_code,',
'       t.due_date,',
'       t.percent_complete,',
'       nvl(u.display_name, ''Unassigned'') as owner_name',
'  from tsk_tasks t',
'  left join tsk_statuses s',
'    on s.status_id = t.status_id',
'  left join tsk_team_members tm',
'    on tm.team_member_id = t.owner_member_id',
'  left join tsk_users u',
'    on u.user_id = tm.user_id',
' where exists (',
'           select 1',
'             from tsk_task_topic_groups ttg',
'            where ttg.task_id = t.task_id',
'              and ttg.topic_group_id = :P80_TOPIC_GROUP_ID',
'       )',
' order by t.due_date nulls last, t.task_key'))
,p_ajax_enabled=>'Y'
,p_ajax_items_to_submit=>'P80_TOPIC_GROUP_ID'
,p_lazy_loading=>false
,p_query_row_template=>2540130677583398057
